## VIDA Instruction Engine — root config instruction catalog/bundle/overlay composition.

import std/[json, strutils]
import ./[kernel_config, utils]

proc defaultBundleName(catalog: JsonNode): string =
  let bundleRef = policyValue(catalog{"default_bundle_ref"}, "")
  if bundleRef.len == 0:
    return "default_runtime"
  let parts = bundleRef.split('/')
  var name = parts[^1]
  if name.endsWith(".yaml"):
    name = name[0 .. ^6]
  elif name.endsWith(".yml"):
    name = name[0 .. ^5]
  name

proc projectOverlayName(catalog: JsonNode): string =
  let overlayRef = policyValue(catalog{"project_overlay_ref"}, "")
  if overlayRef.len == 0:
    return "project_overlay"
  let parts = overlayRef.split('/')
  var name = parts[^1]
  if name.endsWith(".yaml"):
    name = name[0 .. ^6]
  elif name.endsWith(".yml"):
    name = name[0 .. ^5]
  name

proc loadInstructionBundle*(name: string): JsonNode =
  loadKernelArtifact("instructions/bundles", name)

proc loadInstructionOverlay*(name: string): JsonNode =
  loadKernelArtifact("instructions/overlays", name)

proc composeInstructionSurface*(
  role: string,
  machineName: string = "",
  routeName: string = "",
): JsonNode =
  let catalog = loadInstructionCatalog()
  if catalog.kind != JObject or catalog.len == 0:
    return %*{"ok": false, "reason": "missing_instruction_catalog"}

  let roleSpec = dottedGet(catalog, "roles." & role, newJObject())
  if roleSpec.kind != JObject or roleSpec.len == 0:
    return %*{"ok": false, "reason": "unknown_role", "role": role}

  let bundle = loadInstructionBundle(defaultBundleName(catalog))
  let projectOverlay = loadInstructionOverlay(projectOverlayName(catalog))
  let machineSpec =
    if machineName.len > 0: loadMachineSpec(machineName) else: newJObject()
  let routeSpec =
    if routeName.len > 0: dottedGet(loadRouteCatalog(), "routes." & routeName, newJObject())
    else: newJObject()

  result = %*{
    "ok": true,
    "role": role,
    "instruction_catalog": catalog{"artifact_name"},
    "bundle": bundle{"artifact_name"},
    "composition_order": catalog{"composition_order"},
    "bundle_order": bundle{"bundle_order"},
    "role_binding": roleSpec,
    "project_overlay": {
      "artifact_name": projectOverlay{"artifact_name"},
      "project": projectOverlay{"project"},
      "language_policy": projectOverlay{"language_policy"},
      "project_bootstrap": projectOverlay{"project_bootstrap"},
      "autonomous_execution": projectOverlay{"autonomous_execution"},
      "framework_self_diagnosis": projectOverlay{"framework_self_diagnosis"},
    },
    "layers": {
      "system_base": %*{
        "catalog_revision": catalog{"revision"},
      },
      "project_overlay": projectOverlay{"artifact_name"},
      "role_overlay": %role,
      "machine_binding": (if machineSpec.kind == JObject and machineSpec.len > 0: machineSpec{"artifact_name"} else: newJNull()),
      "route_overlay": (if routeSpec.kind == JObject and routeSpec.len > 0: %routeName else: newJNull()),
    },
    "effective_output_contract": roleSpec{"output_contract"},
    "effective_proof_requirements": roleSpec{"proof_requirements"},
  }

  if machineSpec.kind == JObject and machineSpec.len > 0:
    result["machine_binding"] = %*{
      "machine": machineName,
      "entity_type": machineSpec{"entity_type"},
      "guards_catalog": machineSpec{"guards_catalog"},
    }

  if routeSpec.kind == JObject and routeSpec.len > 0:
    result["route_overlay"] = %*{
      "route": routeName,
      "route_stage": routeSpec{"route_stage"},
      "required_roles": routeSpec{"required_roles"},
      "capability": routeSpec{"capability"},
      "independence_class": routeSpec{"independence_class"},
    }

## VIDA Kernel Runtime CLI — root config introspection, assignment, and transition evaluation.

import std/json
import ./[agent_inventory, assignment_engine, instruction_engine, kernel_config, transition_engine, toon, utils]

proc printHelp() =
  echo """
Usage:
  vida-legacy kernel summary
  vida-legacy kernel machine <name> [--json]
  vida-legacy kernel route <name> [--json]
  vida-legacy kernel agents [--json]
  vida-legacy kernel instruction <role> [machine] [route] [--json]
  vida-legacy kernel policy <name> [--json]
  vida-legacy kernel assign lane <lane> [context_json] [--json]
  vida-legacy kernel assign task-class <task_class> [context_json] [--json]
  vida-legacy kernel transition <machine> <current_state> <command> [context_json]
"""

proc emitPayload(payload: JsonNode, asJson: bool) =
  if asJson:
    echo pretty(normalizeJson(payload))
  else:
    echo renderToon(normalizeJson(payload))

proc wantsJson(args: seq[string]): bool =
  for arg in args:
    if arg == "--json":
      return true
  false

proc cmdKernel*(args: seq[string]): int =
  if args.len == 0:
    printHelp()
    return 1

  case args[0]
  of "summary":
    emitPayload(kernelSummary(), wantsJson(args))
    return 0

  of "machine":
    if args.len < 2:
      echo "Usage: vida-legacy kernel machine <name> [--json]"
      return 1
    let payload = loadMachineSpec(args[1])
    if payload.kind != JObject or payload.len == 0:
      echo "unknown machine: " & args[1]
      return 1
    emitPayload(payload, wantsJson(args))
    return 0

  of "route":
    if args.len < 2:
      echo "Usage: vida-legacy kernel route <name> [--json]"
      return 1
    let catalog = loadRouteCatalog()
    let payload = dottedGet(catalog, "routes." & args[1], newJObject())
    if payload.kind != JObject or payload.len == 0:
      echo "unknown route: " & args[1]
      return 1
    emitPayload(%*{"route_name": args[1], "route": payload}, wantsJson(args))
    return 0

  of "agents":
    emitPayload(buildRuntimeAgentInventory(), wantsJson(args))
    return 0

  of "policy":
    if args.len < 2:
      echo "Usage: vida-legacy kernel policy <name> [--json]"
      return 1
    let payload = loadPolicySpec(args[1])
    if payload.kind != JObject or payload.len == 0:
      echo "unknown policy: " & args[1]
      return 1
    emitPayload(payload, wantsJson(args))
    return 0

  of "instruction":
    if args.len < 2:
      echo "Usage: vida-legacy kernel instruction <role> [machine] [route] [--json]"
      return 1
    let machineName =
      if args.len >= 3 and args[2] != "--json": args[2]
      else: ""
    let routeName =
      if args.len >= 4 and args[3] != "--json": args[3]
      else: ""
    let payload = composeInstructionSurface(args[1], machineName, routeName)
    emitPayload(payload, wantsJson(args))
    return (if dottedGetBool(payload, "ok", false): 0 else: 1)

  of "assign":
    if args.len < 3:
      echo "Usage: vida-legacy kernel assign <lane|task-class> <name> [context_json] [--json]"
      return 1
    let ctx =
      if args.len >= 4 and args[3] != "--json":
        try:
          parseJson(args[3])
        except:
          echo "invalid context_json"
          return 1
      else:
        newJObject()
    let payload =
      case args[1]
      of "lane":
        resolveAssignmentForLane(args[2], ctx)
      of "task-class":
        resolveAssignmentForTaskClass(args[2], ctx)
      else:
        echo "Usage: vida-legacy kernel assign <lane|task-class> <name> [context_json] [--json]"
        return 1
    emitPayload(payload, wantsJson(args))
    return (if dottedGetBool(payload, "ok", false): 0 else: 1)

  of "transition":
    if args.len < 4:
      echo "Usage: vida-legacy kernel transition <machine> <current_state> <command> [context_json]"
      return 1
    let machine = loadMachineSpec(args[1])
    if machine.kind != JObject or machine.len == 0:
      echo "unknown machine: " & args[1]
      return 1
    let ctx =
      if args.len >= 5:
        try:
          parseJson(args[4])
        except:
          echo "invalid context_json"
          return 1
      else:
        newJObject()
    let payload = applyTransition(machine, args[2], args[3], ctx)
    emitPayload(payload, wantsJson(args))
    return (if dottedGetBool(payload, "ok", false): 0 else: 1)

  else:
    echo "Unknown kernel subcommand: " & args[0]
    return 1
